public:
    int firstMissingPositive(std::vector<int> nums) {
        std::sort(nums.begin(), nums.end());
        for (int i = 0; i < nums.size(); i++) {
            if (nums[i] > 0) {
                return nums[i];
            }
        }
        return -1;
    }
};

